import { NavLink, Outlet, useNavigate } from "react-router-dom";
import { LayoutDashboard, ArrowLeft } from "lucide-react";

const CONTENT_SECTIONS = [
  { to: "/cms/hero", label: "Hero / Banner" },
  { to: "/cms/siapa-kami", label: "Siapa Kami" },
  { to: "/cms/visi-misi", label: "Visi & Misi" },
  { to: "/cms/nilai", label: "Nilai Perusahaan" },
  { to: "/cms/layanan", label: "Layanan Unggulan" },
  { to: "/cms/kendaraan", label: "Kendaraan Kami" },
  { to: "/cms/testimoni", label: "Testimoni" },
];

const SITE_SETTINGS = [
  { to: "/cms/pengaturan", label: "Pengaturan Umum" },
  { to: "/cms/seo", label: "SEO & Meta" },
];

export default function CMSLayout() {
  const navigate = useNavigate();

  return (
    <div className="flex min-h-screen bg-[#FDFDF9]">
      {/* Left Sidebar */}
      <aside className="w-[260px] bg-white border-r border-gray-200/70 flex flex-col h-screen sticky top-0 shadow-sm z-10">
        {/* Logo Area */}
        <div className="px-6 py-6 flex items-center gap-3 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors" onClick={() => navigate('/dashboard')}>
          <div className="w-10 h-10 rounded bg-[#F5BC00] flex items-center justify-center shadow-sm">
            <span className="text-white font-extrabold text-sm tracking-tight">MPL</span>
          </div>
          <div>
            <h1 className="text-[13px] font-bold text-gray-900 leading-tight">Mandiri Perkasa</h1>
            <p className="text-[11px] text-gray-500">Admin CMS</p>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto py-6 flex flex-col gap-8 custom-scrollbar">
          {/* Content Sections */}
          <div className="px-4">
            <h2 className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-3 px-3">Content Sections</h2>
            <div className="space-y-1">
              {CONTENT_SECTIONS.map((item) => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={({ isActive }) =>
                    `flex items-center px-3 py-2.5 rounded-md text-[13px] font-medium transition-colors ${
                      isActive
                        ? "bg-[#FEF9E6] text-[#D9A500] border-l-2 border-[#F5BC00]"
                        : "text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent"
                    }`
                  }
                >
                  {item.label}
                </NavLink>
              ))}
            </div>
          </div>

          {/* Site Settings */}
          <div className="px-4">
            <h2 className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-3 px-3">Site Settings</h2>
            <div className="space-y-1">
              {SITE_SETTINGS.map((item) => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={({ isActive }) =>
                    `flex items-center px-3 py-2.5 rounded-md text-[13px] font-medium transition-colors ${
                      isActive
                        ? "bg-[#FEF9E6] text-[#D9A500] border-l-2 border-[#F5BC00]"
                        : "text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent"
                    }`
                  }
                >
                  {item.label}
                </NavLink>
              ))}
            </div>
          </div>
        </nav>

        {/* Actions Footer */}
        <div className="p-4 border-t border-gray-100">
          <div className="px-4">
            <h2 className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-3 px-3">Actions</h2>
            <div className="space-y-1">
              <button className="w-full text-left flex items-center px-3 py-2.5 rounded-md text-[13px] font-medium text-gray-600 hover:bg-gray-50 hover:text-gray-900 transition-colors">
                Preview Site
              </button>
              <button className="w-full text-left flex items-center px-3 py-2.5 rounded-md text-[13px] font-medium text-gray-600 hover:bg-gray-50 hover:text-gray-900 transition-colors">
                Backup Data
              </button>
              <button 
                onClick={() => navigate('/dashboard')}
                className="w-full mt-2 flex items-center gap-2 px-3 py-2.5 rounded-md text-[13px] font-medium text-red-600 hover:bg-red-50 transition-colors"
              >
                <ArrowLeft className="w-4 h-4" />
                Kembali ke Admin
              </button>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col min-w-0">
        <Outlet />
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #E5E7EB; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #D1D5DB; }
      `}</style>
    </div>
  );
}
